## 6. gRPC Proto 설계

파일 위치: `/protobuf/src/main/proto/`

### user/user.proto

```protobuf
syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserService {
  rpc GetUser(GetUserRequest) returns (GetUserResponse);
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
}

message UserProto {
  string id = 1;
  string nickname = 2;
  int32 gender = 3;
  int32 birth_year = 4;
  int32 status = 5;
  string created_at = 6;
}

message ProfileProto {
  string id = 1;
  string user_id = 2;
  optional string bio = 3;
  optional string profile_image_url = 4;
  optional string voice_intro_url = 5;
  repeated string interests = 6;
  int32 visibility = 7;
  double manner_score = 8;
}

message GetUserRequest { string user_id = 1; }
message GetUserResponse { UserProto user = 1; }

message GetProfileRequest { string user_id = 1; }
message GetProfileResponse { ProfileProto profile = 1; }

message UpdateProfileRequest {
  string user_id = 1;
  optional string bio = 2;
  optional string profile_image_url = 3;
  optional string voice_intro_url = 4;
  repeated string interests = 5;
  optional int32 visibility = 6;
}
message UpdateProfileResponse { ProfileProto profile = 1; }
```

### matching/matching.proto

```protobuf
syntax = "proto3";
package matching;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.matching";

service MatchingService {
  rpc RequestMatching(RequestMatchingRequest) returns (RequestMatchingResponse);
  rpc AcceptMatching(AcceptMatchingRequest) returns (AcceptMatchingResponse);
  rpc RejectMatching(RejectMatchingRequest) returns (RejectMatchingResponse);
  rpc ListMatchings(ListMatchingsRequest) returns (ListMatchingsResponse);
}

message MatchingProto {
  string id = 1;
  string requester_id = 2;
  string receiver_id = 3;
  int32 status = 4;
  optional string expires_at = 5;
  optional string resolved_at = 6;
  string created_at = 7;
}

message RequestMatchingRequest {
  string requester_id = 1;
  string receiver_id = 2;
}
message RequestMatchingResponse { MatchingProto matching = 1; }

message AcceptMatchingRequest { string user_id = 1; string matching_id = 2; }
message AcceptMatchingResponse { MatchingProto matching = 1; }

message RejectMatchingRequest { string user_id = 1; string matching_id = 2; }
message RejectMatchingResponse { MatchingProto matching = 1; }

message ListMatchingsRequest {
  string user_id = 1;
  optional int32 status = 2;
  int32 limit = 3;
  int32 offset = 4;
}
message ListMatchingsResponse { repeated MatchingProto matchings = 1; }
```

### call/call.proto

```protobuf
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
  rpc InitiateCall(InitiateCallRequest) returns (InitiateCallResponse);
  rpc EndCall(EndCallRequest) returns (EndCallResponse);
  rpc DeclineCall(DeclineCallRequest) returns (DeclineCallResponse);
  rpc ListCallHistory(ListCallHistoryRequest) returns (ListCallHistoryResponse);
  rpc GetMannerScore(GetMannerScoreRequest) returns (GetMannerScoreResponse);
}

message CallProto {
  string id = 1;
  string caller_id = 2;
  string callee_id = 3;
  optional string matching_id = 4;
  int32 status = 5;
  optional string started_at = 6;
  optional string ended_at = 7;
  int32 duration_seconds = 8;
  string created_at = 9;
}

message InitiateCallRequest {
  string caller_id = 1;
  string callee_id = 2;
  optional string matching_id = 3;
}
message InitiateCallResponse { CallProto call = 1; }

message EndCallRequest { string user_id = 1; string call_id = 2; }
message EndCallResponse { CallProto call = 1; }

message DeclineCallRequest { string user_id = 1; string call_id = 2; }
message DeclineCallResponse { CallProto call = 1; }

message ListCallHistoryRequest { string user_id = 1; int32 limit = 2; int32 offset = 3; }
message ListCallHistoryResponse { repeated CallProto calls = 1; }

message GetMannerScoreRequest { string user_id = 1; }
message GetMannerScoreResponse { double manner_score = 1; }
```

### chat/chat.proto

```protobuf
syntax = "proto3";
package chat;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.chat";

service ChatService {
  rpc SendMessage(SendMessageRequest) returns (SendMessageResponse);
  rpc ListMessages(ListMessagesRequest) returns (ListMessagesResponse);
  rpc ListChatRooms(ListChatRoomsRequest) returns (ListChatRoomsResponse);
  rpc MarkAsRead(MarkAsReadRequest) returns (MarkAsReadResponse);
}

message MessageProto {
  string id = 1;
  string chat_room_id = 2;
  string sender_id = 3;
  int32 type = 4;
  string content = 5;
  optional string media_url = 6;
  optional string read_at = 7;
  string created_at = 8;
}

message ChatRoomProto {
  string id = 1;
  string matching_id = 2;
  string user1_id = 3;
  string user2_id = 4;
  int32 status = 5;
  optional string last_message_at = 6;
  string created_at = 7;
}

message SendMessageRequest {
  string sender_id = 1;
  string chat_room_id = 2;
  int32 type = 3;
  string content = 4;
  optional string media_url = 5;
}
message SendMessageResponse { MessageProto message = 1; }

message ListMessagesRequest {
  string user_id = 1;
  string chat_room_id = 2;
  int32 limit = 3;
  optional string before_sort_key = 4;
}
message ListMessagesResponse { repeated MessageProto messages = 1; }

message ListChatRoomsRequest { string user_id = 1; int32 limit = 2; int32 offset = 3; }
message ListChatRoomsResponse { repeated ChatRoomProto chat_rooms = 1; }

message MarkAsReadRequest { string user_id = 1; string chat_room_id = 2; string message_id = 3; }
message MarkAsReadResponse { bool success = 1; }
```

